package main

import (
	"crypto/rand"
	"encoding/hex"
	"errors"
	"net/http"
	"net/url"
	"path"
	"strings"
	"time"

	"github.com/golang-jwt/jwt/v5"
	"golang.org/x/oauth2"
)

var (
	OAuthConfig = &oauth2.Config{
		ClientID:     "your-client-id", // Should be loaded from environment variables in production
		ClientSecret: "your-client-secret", // Should be loaded from environment variables in production
		RedirectURL:  "https://yourapp.com/callback", // Fixed registered redirect URL
		Scopes:       []string{"openid", "profile", "email"},
		Endpoint: oauth2.Endpoint{
			AuthURL:  "https://provider.com/oauth2/authorize",
			TokenURL: "https://provider.com/oauth2/token",
		},
	}
	jwtSecret = []byte("your-strong-jwt-secret-key") // Should be loaded from environment variables in production
)

// OAuthStateClaims contains the state data stored in JWT
type OAuthStateClaims struct {
	RedirectPath string `json:"redirect_path"`
	SessionID    string `json:"session_id"`
	Nonce        string `json:"nonce"`
	jwt.RegisteredClaims
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate session cookie is present
	if session == nil {
		return "", errors.New("session cookie is required")
	}

	// Validate redirect path is safe
	if !isSafeRedirectPath(redirectPath) {
		return "", errors.New("invalid or unsafe redirect path")
	}

	// Generate cryptographically secure random nonce
	nonce, err := generateRandomNonce()
	if err != nil {
		return "", err
	}

	// Create JWT claims for state parameter
	claims := &OAuthStateClaims{
		RedirectPath: redirectPath,
		SessionID:    session.Value,
		Nonce:        nonce,
		RegisteredClaims: jwt.RegisteredClaims{
			ExpiresAt: jwt.NewNumericDate(time.Now().Add(15 * time.Minute)), // Expire after 15 minutes
			IssuedAt:  jwt.NewNumericDate(time.Now()),
			Issuer:    "yourapp.com", // Match your app's domain
		},
	}

	// Sign JWT to create secure state parameter
	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	state, err := token.SignedString(jwtSecret)
	if err != nil {
		return "", err
	}

	// Set nonce cookie for additional CSRF protection
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_nonce",
		Value:    nonce,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
		MaxAge:   900, // 15 minutes (matches JWT expiration)
		Path:     "/",
	})

	// Generate authorization URL using fixed registered redirect URL
	authURL := OAuthConfig.AuthCodeURL(state, oauth2.AccessTypeOnline)

	return authURL, nil
}

// generateRandomNonce creates a 256-bit cryptographically secure random string
func generateRandomNonce() (string, error) {
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	return hex.EncodeToString(b), nil
}

// isSafeRedirectPath validates that the redirect path is a safe relative path
func isSafeRedirectPath(redirectPath string) bool {
	// Reject empty paths
	if redirectPath == "" {
		return false
	}

	// Parse to check for absolute URLs or external domains
	u, err := url.Parse(redirectPath)
	if err != nil || u.IsAbs() || u.Scheme != "" || u.Host != "" {
		return false
	}

	// Clean path to resolve traversal sequences
	cleanedPath := path.Clean(redirectPath)

	// Reject paths that traverse outside the root directory
	if strings.HasPrefix(cleanedPath, "../") || !strings.HasPrefix(cleanedPath, "/") {
		return false
	}

	// Ensure original path doesn't contain hidden traversal sequences
	if cleanedPath != redirectPath {
		return false
	}

	return true
}

