func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
    // Validate session cookie is provided to store CSRF state
    if session == nil {
        return "", errors.New("session cookie is required for CSRF protection")
    }

    // Generate secure random state parameter for CSRF protection
    stateBytes := make([]byte, 32)
    if _, err := rand.Read(stateBytes); err != nil {
        return "", fmt.Errorf("failed to generate OAuth state: %w", err)
    }
    state := base64.URLEncoding.EncodeToString(stateBytes)

    // Build full redirect URL using request context (handles http/https and proxy scenarios)
    scheme := "http"
    if r.TLS != nil {
        scheme = "https"
    }
    // Handle reverse proxy scenario with X-Forwarded-Proto header
    if proto := r.Header.Get("X-Forwarded-Proto"); proto != "" {
        scheme = proto
    }

    redirectURL := &url.URL{
        Scheme: scheme,
        Host:   r.Host,
        Path:   redirectPath,
    }
    fullRedirectURL := redirectURL.String()

    // Create a copy of the global config to avoid concurrent modification
    config := *OAuthConfig
    config.RedirectURL = fullRedirectURL

    // Generate authorization URL with offline access (to obtain refresh token)
    authURL := config.AuthCodeURL(state, oauth2.AccessTypeOffline)

    // Update session cookie with state for later verification
    session.Value = state
    // Set security attributes for the cookie
    session.HttpOnly = true
    session.Secure = scheme == "https" // Only send over HTTPS when using secure scheme
    session.SameSite = http.SameSiteLaxMode
    if session.Path == "" {
        session.Path = "/"
    }
    // Write updated session cookie to response
    http.SetCookie(w, session)

    return authURL, nil
}

