	"crypto/rand"
	"encoding/base64"
	"fmt"
	"net/http"
	"net/url"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate session cookie presence
	if session == nil {
		return "", fmt.Errorf("session cookie cannot be nil")
	}

	// Generate secure random state for CSRF protection
	stateBytes := make([]byte, 32)
	if _, err := rand.Read(stateBytes); err != nil {
		return "", fmt.Errorf("failed to generate CSRF state: %w", err)
	}
	state := base64.URLEncoding.EncodeToString(stateBytes)

	// Parse original redirect URL to modify path safely
	originalRedirectURL, err := url.Parse(OAuthConfig.RedirectURL)
	if err != nil {
		return "", fmt.Errorf("failed to parse original redirect URL: %w", err)
	}

	// Create updated redirect URL with custom path
	newRedirectURL := *originalRedirectURL
	newRedirectURL.Path = redirectPath

	// Create copy of OAuth config to avoid modifying global state
	config := *OAuthConfig
	config.RedirectURL = newRedirectURL.String()

	// Update session cookie with CSRF state and security attributes
	session.Value = state
	session.HttpOnly = true          // Prevent XSS access to cookie
	session.Secure = r.TLS != nil    // Use secure flag for HTTPS requests
	session.SameSite = http.SameSiteLaxMode // Mitigate CSRF attacks
	session.MaxAge = 3600            // Expire after 1 hour

	// Set updated session cookie in response
	http.SetCookie(w, session)

	// Generate final authorization URL
	authURL := config.AuthCodeURL(state)

	return authURL, nil
}

func main() {
	// Example HTTP handler to demonstrate GenerateAuthURL usage
	http.HandleFunc("/auth", func(w http.ResponseWriter, r *http.Request) {
		// Get custom redirect path from query parameter (default to /callback)
		redirectPath := r.URL.Query().Get("redirect_path")
		if redirectPath == "" {
			redirectPath = "/callback"
		}

		// Retrieve or create session cookie
		session, err := r.Cookie("session")
		if err != nil {
			// Create new session cookie if not present
			session = &http.Cookie{
				Name: "session",
				Path: "/",
			}
		}

		// Generate authorization URL
		authURL, err := GenerateAuthURL(redirectPath, session, w, r)
		if err != nil {
			http.Error(w, fmt.Sprintf("Failed to generate auth URL: %v", err), http.StatusInternalServerError)
			return
		}

		// Redirect user to OAuth2 provider's authorization page
		http.Redirect(w, r, authURL, http.StatusFound)
	})

	// Start HTTP server
	fmt.Println("Server starting on :8080...")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server failed to start: %v\n", err)
	}
}

