	"net/http"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// generateRandomState creates a secure random state string for OAuth2 CSRF protection
func generateRandomState() (string, error) {
	const stateLength = 32
	b := make([]byte, stateLength)
	_, err := rand.Read(b)
	if err != nil {
		return "", err
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate session exists
	if session == nil {
		return "", http.ErrNoCookie
	}

	// Generate secure random state for CSRF protection
	state, err := generateRandomState()
	if err != nil {
		return "", err
	}

	// Store redirect path in session-associated cookie for callback retrieval
	http.SetCookie(w, &http.Cookie{
		Name:     "post_auth_redirect",
		Value:    redirectPath,
		HttpOnly: true,
		Secure:   session.Secure,
		SameSite: session.SameSite,
		Path:     "/",
		MaxAge:   session.MaxAge,
	})

	// Store state in cookie for CSRF validation in callback
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   session.Secure,
		SameSite: session.SameSite,
		Path:     "/",
		MaxAge:   3600, // 1 hour expiration for state validation
	})

	// Generate authorization URL with PKCE (recommended for public clients)
	// For confidential clients, you can omit the PKCE parameters if not needed
	codeVerifier, err := generateRandomState()
	if err != nil {
		return "", err
	}
	codeChallenge := base64.RawURLEncoding.EncodeToString([]byte(codeVerifier))

	// Store code verifier in cookie for token exchange
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_code_verifier",
		Value:    codeVerifier,
		HttpOnly: true,
		Secure:   session.Secure,
		SameSite: session.SameSite,
		Path:     "/",
		MaxAge:   3600,
	})

	// Generate authorization URL with state and PKCE challenge
	authURL := OAuthConfig.AuthCodeURL(state,
		oauth2.SetAuthURLParam("code_challenge", codeChallenge),
		oauth2.SetAuthURLParam("code_challenge_method", "S256"),
		oauth2.AccessTypeOffline, // Request refresh token if needed
	)

	return authURL, nil
}

