// StatePayload contains session and redirect information embedded in the OAuth state parameter
type StatePayload struct {
	SessionID    string `json:"s"`
	Nonce        string `json:"n"`
	RedirectPath string `json:"r"`
}

// GenerateAuthURL generates a secure OAuth2 authorization URL with anti-CSRF protection and validated redirect path
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate required session cookie exists
	if session == nil {
		return "", errors.New("missing required session cookie")
	}
	sessionID := session.Value

	// Validate redirect path to prevent open redirect and directory traversal attacks
	if err := validateRedirectPath(redirectPath); err != nil {
		return "", err
	}

	// Generate tamper-proof signed state tied to user session
	state, err := generateSignedState(sessionID, redirectPath)
	if err != nil {
		return "", err
	}

	// Set secure state cookie for CSRF validation in callback
	setStateCookie(state, session, w, r)

	// Generate authorization URL using registered redirect URL (never use user-provided path here)
	authURL := OAuthConfig.AuthCodeURL(state, oauth2.AccessTypeOffline)

	return authURL, nil
}

// validateRedirectPath ensures redirect path is safe and conforms to allowed patterns
func validateRedirectPath(path string) error {
	if !strings.HasPrefix(path, "/") {
		return errors.New("redirect path must be relative and start with '/'")
	}

	// Block directory traversal attempts
	if strings.Contains(path, "../") || strings.Contains(path, "%2e%2e/") {
		return errors.New("redirect path contains invalid directory traversal sequence")
	}

	// Block absolute URLs to prevent open redirect attacks
	if strings.HasPrefix(path, "http://") || strings.HasPrefix(path, "https://") {
		return errors.New("absolute URLs are not allowed in redirect path")
	}

	return nil
}

// generateSignedState creates a tamper-proof state parameter using HMAC-SHA256
func generateSignedState(sessionID, redirectPath string) (string, error) {
	// Generate cryptographically secure nonce
	nonce := make([]byte, 16)
	if _, err := rand.Read(nonce); err != nil {
		return "", err
	}

	// Create payload with session binding and redirect path
	payload := StatePayload{
		SessionID:    sessionID,
		Nonce:        base64.URLEncoding.EncodeToString(nonce),
		RedirectPath: redirectPath,
	}

	// Serialize payload to JSON
	payloadBytes, err := json.Marshal(payload)
	if err != nil {
		return "", err
	}

	// Sign payload with HMAC-SHA256
	mac := hmac.New(sha256.New, stateSecret)
	if _, err := mac.Write(payloadBytes); err != nil {
		return "", err
	}
	signature := mac.Sum(nil)

	// Encode payload and signature for URL safety
	return base64.URLEncoding.EncodeToString(payloadBytes) + "." + base64.URLEncoding.EncodeToString(signature), nil
}

// setStateCookie sets a secure cookie containing the signed state parameter
func setStateCookie(state string, session *http.Cookie, w http.ResponseWriter, r *http.Request) {
	// Determine if secure cookie should be used (HTTPS detection)
	isSecure := r.TLS != nil || strings.EqualFold(r.Header.Get("X-Forwarded-Proto"), "https")

	cookie := &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true, // Prevent JavaScript access
		Secure:   isSecure, // Only send over HTTPS in production
		SameSite: http.SameSiteLaxMode, // Balance security and usability for OAuth flows
		Path:     "/",
		MaxAge:   900, // Expire after 15 minutes (reasonable for OAuth flow)
		Domain:   session.Domain, // Match session cookie's domain
	}

	http.SetCookie(w, cookie)
}

